import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        byte[] encodedBytes = userInput.getBytes(StandardCharsets.UTF_8);
        byte[] buffer = new byte[10];

        int length = Math.min(encodedBytes.length, buffer.length);
        System.arraycopy(encodedBytes, 0, buffer, 0, length);

        String sanitizedInput = new String(buffer, StandardCharsets.UTF_8);

        System.out.println("Buffer content: " + sanitizedInput);
    }
}

